// Home page - shows hero section and some featured products
import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

function Home() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  // get products from backend when page loads
  useEffect(() => {
    console.log('Home page - fetching products...');
    fetch('/products')
      .then(function(res) {
        return res.json();
      })
      .then(function(data) {
        console.log('got products:', data);
        // only show first 3 products as featured
        setProducts(data.slice(0, 3));
        setLoading(false);
      })
      .catch(function(err) {
        console.log('error getting products:', err);
        setLoading(false);
      });
  }, []);

  // add to cart function
  function addToCart(product) {
    var cart = JSON.parse(localStorage.getItem('cart')) || [];
    var found = cart.find(function(item) { return item.id === product.id; });

    if (found) {
      found.quantity = found.quantity + 1;
    } else {
      product.quantity = 1;
      cart.push(product);
    }

    localStorage.setItem('cart', JSON.stringify(cart));
    alert(product.name + ' added to cart!');
  }

  return (
    <div>
      {/* hero section */}
      <div className="hero-section">
        <h1>Welcome to Sahs Accessories</h1>
        <p>Find the best tech accessories at affordable prices</p>
        <Link to="/products" className="btn btn-primary btn-lg">Shop Now</Link>
      </div>

      {/* featured products */}
      <div className="container mt-5">
        <h2>Featured Products</h2>
        <p className="text-muted">Check out our popular products</p>
        <hr />

        {loading ? (
          <p>Loading products please wait...</p>
        ) : (
          <div className="row">
            {products.map(function(product) {
              return (
                <div key={product.id} className="col-md-4 mb-4">
                  <div className="card h-100">
                    <img
                      src={'/images/' + product.image}
                      className="card-img-top"
                      alt={product.name}
                    />
                    <div className="card-body">
                      <h5 className="card-title">{product.name}</h5>
                      <p className="text-success fw-bold">${product.price}</p>
                      <div className="d-flex gap-2">
                        <Link to={'/product/' + product.id} className="btn btn-outline-primary btn-sm">
                          View Details
                        </Link>
                        <button
                          className="btn btn-success btn-sm"
                          onClick={function() { addToCart(product); }}
                        >
                          Add to Cart
                        </button>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}

        <div className="text-center mt-3">
          <Link to="/products" className="btn btn-dark">See All Products</Link>
        </div>
      </div>

      {/* simple info section */}
      <div className="container mt-5">
        <div className="row text-center">
          <div className="col-md-4 mb-3">
            <div className="card p-4">
              <h4>🚚 Fast Delivery</h4>
              <p>We deliver quickly to your door</p>
            </div>
          </div>
          <div className="col-md-4 mb-3">
            <div className="card p-4">
              <h4>✅ Good Quality</h4>
              <p>All products are tested and good quality</p>
            </div>
          </div>
          <div className="col-md-4 mb-3">
            <div className="card p-4">
              <h4>📞 Support</h4>
              <p>We are here to help you anytime</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
